from pathlib import Path
from datetime import datetime

ROOT = Path(__file__).resolve().parent
BACKEND = ROOT / "backend"
APP = BACKEND / "app"
SERVICES = APP / "services"

MAIN_PATH = APP / "main.py"
ORACLE_PATH = SERVICES / "oracle_service.py"
NLP_PATH = SERVICES / "nlp_service.py"
DYNAMIC_PATH = SERVICES / "dynamic_guardrails_service.py"

BACKUP_SUFFIX = ".bak_stabilize_no_rewrite"

MAIN_CONTENT = 'import time\nimport hashlib\nfrom threading import Lock, Thread\nfrom uuid import uuid4\n\nfrom fastapi import Depends, FastAPI, Header, HTTPException, Query, status\nfrom fastapi.middleware.cors import CORSMiddleware\n\nfrom app.config import settings\nfrom app.schemas import (\n    AdminUser,\n    AuditLogEntry,\n    AuthUser,\n    HealthResponse,\n    LoginRequest,\n    LoginResponse,\n    MetadataResponse,\n    QueryRequest,\n    QueryProgressResponse,\n    QueryProgressStep,\n    QueryResponse,\n    QueryStartResponse,\n    RuntimeSettings,\n    UserCreateRequest,\n    UserStatusUpdateRequest,\n)\nfrom app.services.audit_service import init_audit_db, read_audit_logs, write_audit_log\nfrom app.services.auth_service import (\n    authenticate_user,\n    create_session,\n    create_user,\n    delete_user,\n    ensure_default_admin_access,\n    get_user_by_token,\n    init_auth_db,\n    list_users,\n    revoke_session,\n    set_user_active,\n)\nfrom app.services.nlp_service import generate_sql_from_question, model_status\nfrom app.services.oracle_service import execute_sql, fetch_metadata, get_connection, oracle_status\nfrom app.services.settings_service import get_fetch_limit, get_runtime_settings, update_runtime_settings\nfrom app.services.synthesis_service import build_synthesis, phi3_status\n\napp = FastAPI(title="SMART2D Backend API", version="0.1.0")\n\nQUERY_HISTORY: list[dict] = []\nMAX_CONCURRENT_QUERIES_PER_USER = max(1, settings.max_concurrent_queries_per_user)\n_ACTIVE_USER_QUERIES: dict[str, int] = {}\n_ACTIVE_USER_QUERIES_LOCK = Lock()\n_QUERY_PROGRESS: dict[str, dict] = {}\n_QUERY_PROGRESS_LOCK = Lock()\n\n# Query response cache (TTL: 3600s = 1 hour, max ~256MB)\nimport sys\n_QUERY_CACHE: dict[str, tuple[QueryResponse, float]] = {}  # {hash: (response, timestamp)}\n_QUERY_CACHE_LOCK = Lock()\n_QUERY_CACHE_TTL_SECONDS = 3600\n_QUERY_CACHE_MAX_BYTES = 256 * 1024 * 1024  # 256 MB\n\nQUERY_STAGE_DEFS = [\n    ("generate_sql", "Generation SQL", "Transformation de la question en requete Oracle"),\n    ("connect_oracle", "Connexion Oracle", "Ouverture de la connexion a la base d audit"),\n    ("execute_sql", "Execution", "Lecture des donnees correspondant a la demande"),\n    ("build_synthesis", "Traduction", "Transformation de la reponse brute en resume clair"),\n    ("finalize", "Finalisation", "Preparation des resultats pour l interface"),\n]\n\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=settings.cors_origins,\n    allow_credentials=True,\n    allow_methods=["*"],\n    allow_headers=["*"],\n)\n\n\n@app.on_event("startup")\ndef startup() -> None:\n    init_auth_db()\n    init_audit_db()\n    # Warmup: preload models on startup to avoid cold start for first user\n    print("[STARTUP] Warming up TinyLlama...")\n    try:\n        status, err = model_status()\n        print(f"[STARTUP] TinyLlama status: {status}" + (f" ({err})" if err else ""))\n    except Exception as e:\n        print(f"[STARTUP] TinyLlama warmup error: {e}")\n    \n    print("[STARTUP] Warming up Phi-3...")\n    try:\n        status, err = phi3_status()\n        print(f"[STARTUP] Phi-3 status: {status}" + (f" ({err})" if err else ""))\n    except Exception as e:\n        print(f"[STARTUP] Phi-3 warmup error: {e}")\n\n\ndef _get_query_cache_key(question: str) -> str:\n    """Generate cache key from normalized question."""\n    normalized = question.lower().strip()\n    return hashlib.md5(normalized.encode()).hexdigest()\n\n\ndef _get_cached_response(question: str) -> QueryResponse | None:\n    """Retrieve cached response if exists and not expired."""\n    key = _get_query_cache_key(question)\n    with _QUERY_CACHE_LOCK:\n        if key in _QUERY_CACHE:\n            response, timestamp = _QUERY_CACHE[key]\n            elapsed = time.time() - timestamp\n            if elapsed < _QUERY_CACHE_TTL_SECONDS:\n                print(f"[CACHE_HIT] question (cached {elapsed:.1f}s ago)")\n                return response\n            else:\n                # Expired, remove\n                del _QUERY_CACHE[key]\n    return None\n\n\ndef _estimate_cache_size() -> int:\n    """Rough estimate of cache memory usage in bytes."""\n    total = 0\n    for key, (resp, _ts) in _QUERY_CACHE.items():\n        total += sys.getsizeof(key)\n        total += sys.getsizeof(resp.question) + sys.getsizeof(resp.sql) + sys.getsizeof(resp.synthesis)\n        for row in resp.rows:\n            total += sum(sys.getsizeof(str(v)) for v in row.values())\n    return total\n\n\ndef _cache_response(question: str, response: QueryResponse) -> None:\n    """Store response in cache with timestamp. Evict oldest 50% if size exceeds 256MB."""\n    key = _get_query_cache_key(question)\n    with _QUERY_CACHE_LOCK:\n        _QUERY_CACHE[key] = (response, time.time())\n        # Evict oldest 50% if cache exceeds max size\n        if _estimate_cache_size() > _QUERY_CACHE_MAX_BYTES:\n            sorted_keys = sorted(_QUERY_CACHE.keys(), key=lambda k: _QUERY_CACHE[k][1])\n            to_remove = len(sorted_keys) // 2\n            for k in sorted_keys[:to_remove]:\n                del _QUERY_CACHE[k]\n            print(f"[CACHE_EVICT] Removed {to_remove} oldest entries to free memory")\n\n\ndef _to_auth_user(user: dict) -> AuthUser:\n    return AuthUser(\n        id=int(user["id"]),\n        username=str(user["username"]),\n        is_admin=bool(user["is_admin"]),\n        is_active=bool(user["is_active"]),\n    )\n\n\ndef _acquire_user_query_slot(username: str) -> bool:\n    with _ACTIVE_USER_QUERIES_LOCK:\n        current = _ACTIVE_USER_QUERIES.get(username, 0)\n        if current >= MAX_CONCURRENT_QUERIES_PER_USER:\n            return False\n        _ACTIVE_USER_QUERIES[username] = current + 1\n        return True\n\n\ndef _release_user_query_slot(username: str) -> None:\n    with _ACTIVE_USER_QUERIES_LOCK:\n        current = _ACTIVE_USER_QUERIES.get(username, 0)\n        if current <= 1:\n            _ACTIVE_USER_QUERIES.pop(username, None)\n        else:\n            _ACTIVE_USER_QUERIES[username] = current - 1\n\n\ndef _empty_progress_steps() -> list[dict]:\n    return [\n        {\n            "key": key,\n            "label": label,\n            "summary": summary,\n            "status": "pending",\n            "duration_seconds": None,\n        }\n        for key, label, summary in QUERY_STAGE_DEFS\n    ]\n\n\ndef _init_query_progress(request_id: str, username: str, question: str) -> None:\n    with _QUERY_PROGRESS_LOCK:\n        _QUERY_PROGRESS[request_id] = {\n            "request_id": request_id,\n            "username": username,\n            "question": question,\n            "status": "running",\n            "current_step": None,\n            "current_summary": "Initialisation de l analyse",\n            "elapsed_seconds": 0.0,\n            "steps": _empty_progress_steps(),\n            "result": None,\n            "error": None,\n            "started_at": time.perf_counter(),\n        }\n\n\ndef _update_query_progress(\n    request_id: str,\n    *,\n    stage_key: str | None = None,\n    stage_status: str | None = None,\n    duration_seconds: float | None = None,\n    current_summary: str | None = None,\n    status: str | None = None,\n    result: QueryResponse | None = None,\n    error: str | None = None,\n) -> None:\n    with _QUERY_PROGRESS_LOCK:\n        payload = _QUERY_PROGRESS.get(request_id)\n        if payload is None:\n            return\n\n        now_elapsed = max(0.0, time.perf_counter() - payload["started_at"])\n        payload["elapsed_seconds"] = now_elapsed\n\n        if status is not None:\n            payload["status"] = status\n        if current_summary is not None:\n            payload["current_summary"] = current_summary\n        if error is not None:\n            payload["error"] = error\n        if result is not None:\n            payload["result"] = result.model_dump()\n\n        if stage_key is not None:\n            payload["current_step"] = stage_key\n            for step in payload["steps"]:\n                if step["key"] == stage_key:\n                    if stage_status is not None:\n                        step["status"] = stage_status\n                    if duration_seconds is not None:\n                        step["duration_seconds"] = round(duration_seconds, 3)\n                    break\n\n\ndef _query_progress_response(payload: dict) -> QueryProgressResponse:\n    steps = [QueryProgressStep(**step) for step in payload["steps"]]\n    result = QueryResponse(**payload["result"]) if payload.get("result") else None\n    return QueryProgressResponse(\n        request_id=str(payload["request_id"]),\n        status=str(payload["status"]),\n        current_step=payload.get("current_step"),\n        current_summary=payload.get("current_summary"),\n        elapsed_seconds=float(payload.get("elapsed_seconds") or 0.0),\n        steps=steps,\n        result=result,\n        error=payload.get("error"),\n    )\n\n\ndef _execute_sql_with_progress(sql: str, request_id: str) -> tuple[list[dict], str | None]:\n    conn = None\n    cur = None\n    t_connect_start = time.perf_counter()\n    try:\n        _update_query_progress(\n            request_id,\n            stage_key="connect_oracle",\n            stage_status="running",\n            current_summary="Connexion a Oracle en cours",\n        )\n        conn = get_connection()\n        t_connect_end = time.perf_counter()\n        _update_query_progress(\n            request_id,\n            stage_key="connect_oracle",\n            stage_status="completed",\n            duration_seconds=t_connect_end - t_connect_start,\n            current_summary="Connexion Oracle etablie",\n        )\n\n        _update_query_progress(\n            request_id,\n            stage_key="execute_sql",\n            stage_status="running",\n            current_summary="Execution de la requete sur les donnees d audit",\n        )\n        t_exec_start = time.perf_counter()\n        cur = conn.cursor()\n        cur.execute(sql.rstrip().rstrip(";"))\n        cols = [d[0].upper() for d in cur.description]\n        rows = cur.fetchall()\n        payload = [dict(zip(cols, row)) for row in rows]\n        t_exec_end = time.perf_counter()\n        _update_query_progress(\n            request_id,\n            stage_key="execute_sql",\n            stage_status="completed",\n            duration_seconds=t_exec_end - t_exec_start,\n            current_summary=f"Execution terminee, {len(payload)} ligne(s) trouvee(s)",\n        )\n        return payload, None\n    except Exception as exc:\n        current_key = "execute_sql" if conn is not None else "connect_oracle"\n        _update_query_progress(\n            request_id,\n            stage_key=current_key,\n            stage_status="error",\n            current_summary="Erreur pendant l acces Oracle",\n            error=str(exc),\n        )\n        return [], str(exc)\n    finally:\n        if cur is not None:\n            cur.close()\n        if conn is not None:\n            conn.close()\n\n\ndef _execute_query_pipeline(req: QueryRequest, username: str, request_id: str | None = None) -> QueryResponse:\n    """Execute query pipeline with full resource allocation for optimal model performance."""\n    t0 = time.perf_counter()\n\n    if request_id is not None:\n        _update_query_progress(\n            request_id,\n            stage_key="generate_sql",\n            stage_status="running",\n            current_summary="Generation de la requete SQL en cours",\n        )\n\n    t_sql_start = time.perf_counter()\n    sql = generate_sql_from_question(req.question)\n    t_sql_end = time.perf_counter()\n\n    if request_id is not None:\n        _update_query_progress(\n            request_id,\n            stage_key="generate_sql",\n            stage_status="completed",\n            duration_seconds=t_sql_end - t_sql_start,\n            current_summary="Requete SQL generee",\n        )\n\n    if request_id is not None:\n        rows, error = _execute_sql_with_progress(sql, request_id)\n    else:\n        rows, error = execute_sql(sql)\n\n    blocked = False\n\n    if request_id is not None:\n        _update_query_progress(\n            request_id,\n            stage_key="build_synthesis",\n            stage_status="running",\n            current_summary="Traduction de la reponse brute en langage clair",\n        )\n\n    t_syn_start = time.perf_counter()\n    synthesis = build_synthesis(req.question, rows, error)\n    t_syn_end = time.perf_counter()\n\n    if request_id is not None:\n        _update_query_progress(\n            request_id,\n            stage_key="build_synthesis",\n            stage_status="completed",\n            duration_seconds=t_syn_end - t_syn_start,\n            current_summary="Synthese terminee",\n        )\n        _update_query_progress(\n            request_id,\n            stage_key="finalize",\n            stage_status="running",\n            current_summary="Preparation de la reponse finale",\n        )\n\n    t_post_start = time.perf_counter()\n    fetch_limit = get_fetch_limit()\n\n    entry = {\n        "timestamp": int(time.time()),\n        "username": username,\n        "question": req.question,\n        "sql": sql,\n        "synthesis": synthesis,\n        "row_count": len(rows),\n        "blocked": blocked,\n        "error": error,\n    }\n    QUERY_HISTORY.append(entry)\n    if len(QUERY_HISTORY) > 200:\n        del QUERY_HISTORY[:-200]\n\n    status_value = "ok"\n    detail_value = "Execution terminee"\n    if error:\n        status_value = "error"\n        detail_value = error\n\n    write_audit_log(\n        username=username,\n        action="query_execute",\n        result_status=status_value,\n        question=req.question,\n        sql_text=sql,\n        row_count=len(rows),\n        details=detail_value,\n    )\n\n    response = QueryResponse(\n        question=req.question,\n        sql=sql,\n        synthesis=synthesis,\n        rows=rows[:fetch_limit],\n        row_count=len(rows),\n        blocked=blocked,\n        error=error,\n    )\n\n    t_post_end = time.perf_counter()\n    t_total = t_post_end - t0\n    print(\n        "[QUERY_TIMING] "\n        f"user={username} "\n        f"question_len={len(req.question)} "\n        f"total={t_total:.3f}s "\n        f"generate_sql={t_sql_end - t_sql_start:.3f}s "\n        f"execute_oracle={t_syn_start - t_sql_end:.3f}s "\n        f"build_synthesis={t_syn_end - t_syn_start:.3f}s "\n        f"history_audit={t_post_end - t_post_start:.3f}s "\n        f"rows={len(rows)} "\n        f"error={\'yes\' if error else \'no\'}"\n    )\n\n    if request_id is not None:\n        _update_query_progress(\n            request_id,\n            stage_key="finalize",\n            stage_status="completed",\n            duration_seconds=t_post_end - t_post_start,\n            current_summary="Analyse terminee",\n            status="completed",\n            result=response,\n        )\n\n    return response\n\n\ndef _run_tracked_query(request_id: str, req: QueryRequest, username: str) -> None:\n    try:\n        result = _execute_query_pipeline(req, username, request_id=request_id)\n        _cache_response(req.question, result)\n        _update_query_progress(request_id, status="completed", result=result)\n    except Exception as exc:\n        _update_query_progress(\n            request_id,\n            status="error",\n            current_summary="Analyse interrompue",\n            error=str(exc),\n        )\n    finally:\n        _release_user_query_slot(username)\n\n\ndef get_current_user(x_auth_token: str | None = Header(default=None, alias="X-Auth-Token")) -> dict:\n    if not x_auth_token:\n        raise HTTPException(\n            status_code=status.HTTP_401_UNAUTHORIZED,\n            detail="Token manquant",\n        )\n    user = get_user_by_token(x_auth_token)\n    if user is None:\n        raise HTTPException(\n            status_code=status.HTTP_401_UNAUTHORIZED,\n            detail="Session invalide ou expiree",\n        )\n    return user\n\n\ndef get_admin_user(current_user: dict = Depends(get_current_user)) -> dict:\n    if not bool(current_user["is_admin"]):\n        raise HTTPException(\n            status_code=status.HTTP_403_FORBIDDEN,\n            detail="Acces reserve administrateur",\n        )\n    return current_user\n\n\n@app.post("/api/auth/login", response_model=LoginResponse)\ndef auth_login(payload: LoginRequest) -> LoginResponse:\n    ensure_default_admin_access(payload.username, payload.password)\n    user = authenticate_user(payload.username, payload.password)\n    if user is None:\n        write_audit_log(\n            username=payload.username,\n            action="auth_login",\n            result_status="error",\n            details="Identifiants invalides ou compte suspendu",\n        )\n        raise HTTPException(\n            status_code=status.HTTP_401_UNAUTHORIZED,\n            detail="Identifiants invalides ou compte suspendu",\n        )\n    token = create_session(int(user["id"]))\n    write_audit_log(\n        username=str(user["username"]),\n        action="auth_login",\n        result_status="ok",\n        details="Connexion reussie",\n    )\n    return LoginResponse(token=token, user=_to_auth_user(user))\n\n\n@app.get("/api/auth/me", response_model=AuthUser)\ndef auth_me(current_user: dict = Depends(get_current_user)) -> AuthUser:\n    return _to_auth_user(current_user)\n\n\n@app.post("/api/auth/logout")\ndef auth_logout(x_auth_token: str | None = Header(default=None, alias="X-Auth-Token")) -> dict:\n    user = get_user_by_token(x_auth_token or "") if x_auth_token else None\n    if x_auth_token:\n        revoke_session(x_auth_token)\n    if user is not None:\n        write_audit_log(\n            username=str(user["username"]),\n            action="auth_logout",\n            result_status="ok",\n            details="Deconnexion utilisateur",\n        )\n    return {"status": "ok"}\n\n\n@app.get("/api/admin/users", response_model=list[AdminUser])\ndef admin_list_users(_: dict = Depends(get_admin_user)) -> list[AdminUser]:\n    return [AdminUser(**u) for u in list_users()]\n\n\n@app.post("/api/admin/users", response_model=AdminUser)\ndef admin_create_user(payload: UserCreateRequest, current_admin: dict = Depends(get_admin_user)) -> AdminUser:\n    try:\n        created = create_user(payload.username, payload.password, payload.is_admin)\n        write_audit_log(\n            username=str(current_admin["username"]),\n            action="admin_create_user",\n            result_status="ok",\n            details=f"Utilisateur cree: {payload.username}",\n        )\n    except ValueError as exc:\n        write_audit_log(\n            username=str(current_admin["username"]),\n            action="admin_create_user",\n            result_status="error",\n            details=str(exc),\n        )\n        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail=str(exc)) from exc\n    return AdminUser(**created)\n\n\n@app.patch("/api/admin/users/{user_id}/status", response_model=AdminUser)\ndef admin_set_user_status(\n    user_id: int,\n    payload: UserStatusUpdateRequest,\n    current_admin: dict = Depends(get_admin_user),\n) -> AdminUser:\n    if int(current_admin["id"]) == user_id and not payload.is_active:\n        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Impossible de suspendre votre propre compte")\n\n    updated = set_user_active(user_id, payload.is_active)\n    if updated is None:\n        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Utilisateur introuvable")\n    write_audit_log(\n        username=str(current_admin["username"]),\n        action="admin_set_user_status",\n        result_status="ok",\n        details=f"User={updated[\'username\']} status={\'active\' if payload.is_active else \'suspended\'}",\n    )\n    return AdminUser(**updated)\n\n\n@app.delete("/api/admin/users/{user_id}")\ndef admin_delete_user(user_id: int, current_admin: dict = Depends(get_admin_user)) -> dict:\n    if int(current_admin["id"]) == user_id:\n        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Impossible de supprimer votre propre compte")\n\n    ok = delete_user(user_id)\n    if not ok:\n        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Utilisateur introuvable")\n    write_audit_log(\n        username=str(current_admin["username"]),\n        action="admin_delete_user",\n        result_status="ok",\n        details=f"User id supprime={user_id}",\n    )\n    return {"status": "ok"}\n\n\n@app.get("/api/admin/audit-logs", response_model=list[AuditLogEntry])\ndef admin_audit_logs(\n    limit: int = Query(default=300, ge=1, le=2000),\n    _: dict = Depends(get_admin_user),\n) -> list[AuditLogEntry]:\n    return [AuditLogEntry(**row) for row in read_audit_logs(limit)]\n\n\n@app.get("/api/health", response_model=HealthResponse)\ndef health(_: dict = Depends(get_current_user)) -> HealthResponse:\n    oracle = oracle_status()\n    tinyllama, _ = model_status()\n    phi3, _ = phi3_status()\n    return HealthResponse(status="ok", oracle=oracle, tinyllama=tinyllama, phi3=phi3)\n\n\n@app.get("/api/metadata", response_model=MetadataResponse)\ndef metadata(_: dict = Depends(get_current_user)) -> MetadataResponse:\n    users, objects, db_status = fetch_metadata()\n    return MetadataResponse(users=users, objects=objects, db_status=db_status)\n\n\n@app.get("/api/history")\ndef history(current_user: dict = Depends(get_current_user)) -> list[dict]:\n    user_entries = [h for h in QUERY_HISTORY if h.get("username") == current_user["username"]]\n    return user_entries[-100:]\n\n\n@app.get("/api/settings", response_model=RuntimeSettings)\ndef read_settings(_: dict = Depends(get_current_user)) -> RuntimeSettings:\n    return RuntimeSettings(**get_runtime_settings())\n\n\n@app.post("/api/settings", response_model=RuntimeSettings)\ndef write_settings(payload: RuntimeSettings, current_user: dict = Depends(get_current_user)) -> RuntimeSettings:\n    payload_data = payload.model_dump()\n\n    # Les utilisateurs simples peuvent modifier les paramètres non sensibles,\n    # mais ne peuvent pas écraser la connexion Oracle côté API.\n    if not bool(current_user.get("is_admin")):\n        current_settings = get_runtime_settings()\n        for key in (\n            "oracle_user",\n            "oracle_password",\n            "oracle_host",\n            "oracle_port",\n            "oracle_service",\n            "oracle_table",\n        ):\n            if key in current_settings:\n                payload_data[key] = current_settings[key]\n\n    updated = update_runtime_settings(payload_data)\n    write_audit_log(\n        username=str(current_user["username"]),\n        action="settings_update",\n        result_status="ok",\n        details="Parametres mis a jour",\n    )\n    return RuntimeSettings(**updated)\n\n\n@app.post("/api/query", response_model=QueryResponse)\ndef query(req: QueryRequest, current_user: dict = Depends(get_current_user)) -> QueryResponse:\n    username = str(current_user["username"])\n    \n    # Check response cache first (no compute needed)\n    cached_response = _get_cached_response(req.question)\n    if cached_response is not None:\n        return cached_response\n    \n    if not _acquire_user_query_slot(username):\n        raise HTTPException(\n            status_code=status.HTTP_429_TOO_MANY_REQUESTS,\n            detail="Une autre analyse est deja en cours pour cet utilisateur",\n        )\n\n    try:\n        response = _execute_query_pipeline(req, username)\n        # Cache the response for future identical questions\n        _cache_response(req.question, response)\n        return response\n    except Exception as exc:\n        print(\n            "[QUERY_TIMING] "\n            f"user={username} "\n            f"error={type(exc).__name__}: {exc}"\n        )\n        raise\n    finally:\n        _release_user_query_slot(username)\n\n\n@app.post("/api/query/start", response_model=QueryStartResponse)\ndef query_start(req: QueryRequest, current_user: dict = Depends(get_current_user)) -> QueryStartResponse:\n    username = str(current_user["username"])\n\n    # Check cache first — return instantly if we already have this answer\n    cached_response = _get_cached_response(req.question)\n    if cached_response is not None:\n        request_id = uuid4().hex\n        _init_query_progress(request_id, username, req.question)\n        _update_query_progress(request_id, status="completed", result=cached_response,\n                               current_summary="Reponse depuis le cache")\n        return QueryStartResponse(request_id=request_id)\n\n    if not _acquire_user_query_slot(username):\n        raise HTTPException(\n            status_code=status.HTTP_429_TOO_MANY_REQUESTS,\n            detail="Une autre analyse est deja en cours pour cet utilisateur",\n        )\n\n    request_id = uuid4().hex\n    _init_query_progress(request_id, username, req.question)\n    thread = Thread(target=_run_tracked_query, args=(request_id, req, username), daemon=True)\n    thread.start()\n    return QueryStartResponse(request_id=request_id)\n\n\n@app.get("/api/query/progress/{request_id}", response_model=QueryProgressResponse)\ndef query_progress(request_id: str, current_user: dict = Depends(get_current_user)) -> QueryProgressResponse:\n    username = str(current_user["username"])\n    with _QUERY_PROGRESS_LOCK:\n        payload = _QUERY_PROGRESS.get(request_id)\n        if payload is None:\n            raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Suivi introuvable")\n        if str(payload.get("username")) != username:\n            raise HTTPException(status_code=status.HTTP_403_FORBIDDEN, detail="Acces refuse a ce suivi")\n        payload["elapsed_seconds"] = max(0.0, time.perf_counter() - payload["started_at"])\n        return _query_progress_response(payload)\n\n'

ORACLE_CONTENT = 'try:\n    import oracledb\n\n    _ORACLE_DRIVER_OK = True\nexcept Exception:\n    oracledb = None\n    _ORACLE_DRIVER_OK = False\n\nimport time as time_module\nfrom threading import Lock\n\nfrom app.config import settings\nfrom app.services.settings_service import get_oracle_connection_config, get_oracle_table\n\n\n_POOL = None\n_POOL_CFG: tuple[str, str, str, int, str] | None = None\n_POOL_LOCK = Lock()\n\n# Metadata cache (TTL: 300s = 5 min)\n_METADATA_CACHE: tuple[list[dict], list[dict], str, float] | None = None\n_METADATA_CACHE_LOCK = Lock()\n_METADATA_CACHE_TTL_SECONDS = 300\n\n# Ces filtres servent uniquement à nettoyer les colonnes d\'aide de l\'interface.\n# Ils ne doivent jamais être injectés dans les vraies requêtes utilisateur.\nHIDDEN_OBJECTS_EXACT = {\n    "AUD$",\n    "DEVICE_ADDRESS",\n    "SMA_MIGRATION_17_TEST",\n    "PROD1_UMS",\n    "MGMT_VIEW",\n    "USER_DEVICE",\n    "COMPONENT_SCHEMA_INFO",\n    "ADD_JOB_HISTORY",\n    "SYSMAN",\n    "COMP_PROFILE_TEST",\n    "VROMUALD",\n    "TEST",\n}\n\nHIDDEN_OBJECTS_LIKE = (\n    "SCHEMA_VERSION_REGIST%",\n    "TEST%",\n    "%VROMUALD%",\n    "%ROMUALD%",\n    "BIN$%",\n    "SYS_EXPORT%",\n)\n\n# Utilisateurs historiques/bruités à masquer dans la colonne d\'aide.\n# Les nouveaux utilisateurs apparaissent automatiquement s\'ils ne sont pas ici.\nHIDDEN_USERS_EXACT = {\n    "PROD2_MDS",\n    "PROD2_STB",\n    "TEST",\n    "SMART2DADMIN",\n    "SMART2DADMINI",\n    "SMART2DSECU",\n    "BATCH_USER",\n    "\\\\SMART2DADMIN",\n}\n\n\ndef _sql_list(values: set[str] | tuple[str, ...]) -> str:\n    return ", ".join("\'" + str(v).replace("\'", "\'\'").upper() + "\'" for v in values)\n\n\ndef _hidden_objects_condition(column: str = "OBJECT_NAME") -> str:\n    clauses = [f"{column} IS NOT NULL"]\n    if HIDDEN_OBJECTS_EXACT:\n        clauses.append(f"UPPER({column}) NOT IN ({_sql_list(HIDDEN_OBJECTS_EXACT)})")\n    for pattern in HIDDEN_OBJECTS_LIKE:\n        safe_pattern = pattern.replace("\'", "\'\'").upper()\n        clauses.append(f"UPPER({column}) NOT LIKE \'{safe_pattern}\'")\n    return " AND ".join(clauses)\n\n\ndef _hidden_users_condition(column: str = "DBUSERNAME") -> str:\n    clauses = [f"{column} IS NOT NULL"]\n    if HIDDEN_USERS_EXACT:\n        clauses.append(f"UPPER({column}) NOT IN ({_sql_list(HIDDEN_USERS_EXACT)})")\n    return " AND ".join(clauses)\n\n\ndef clear_metadata_cache() -> None:\n    global _METADATA_CACHE\n    with _METADATA_CACHE_LOCK:\n        _METADATA_CACHE = None\n\n\ndef _build_connection_config() -> tuple[str, str, str, int, str]:\n    user, password, host, port, service = get_oracle_connection_config()\n    return user, password, host, int(port), service\n\n\ndef _create_pool(cfg: tuple[str, str, str, int, str]):\n    user, password, host, port, service = cfg\n    dsn = f"{host}:{port}/{service}"\n    return oracledb.create_pool(\n        user=user,\n        password=password,\n        dsn=dsn,\n        min=max(1, settings.oracle_pool_min),\n        max=max(2, settings.oracle_pool_max),\n        increment=max(1, settings.oracle_pool_increment),\n    )\n\n\ndef _get_pool():\n    global _POOL, _POOL_CFG\n    cfg = _build_connection_config()\n\n    with _POOL_LOCK:\n        if _POOL is None or _POOL_CFG != cfg:\n            if _POOL is not None:\n                try:\n                    _POOL.close(force=True)\n                except Exception:\n                    pass\n            _POOL = _create_pool(cfg)\n            _POOL_CFG = cfg\n        return _POOL\n\n\ndef get_connection():\n    if not _ORACLE_DRIVER_OK:\n        raise RuntimeError("oracledb package is not installed")\n    pool = _get_pool()\n    return pool.acquire()\n\n\ndef execute_sql(sql: str) -> tuple[list[dict], str | None]:\n    """Exécute uniquement le SQL produit par le modèle, sans ajout de filtre métier.\n\n    Les filtres d\'affichage des colonnes Users/Tables ne doivent pas modifier les vraies réponses.\n    """\n    conn = None\n    cur = None\n    try:\n        conn = get_connection()\n        cur = conn.cursor()\n        cur.execute(sql.rstrip().rstrip(";"))\n        cols = [d[0].upper() for d in cur.description]\n        rows = cur.fetchall()\n        payload = [dict(zip(cols, row)) for row in rows]\n        return payload, None\n    except Exception as exc:\n        return [], str(exc)\n    finally:\n        if cur is not None:\n            cur.close()\n        if conn is not None:\n            conn.close()\n\n\ndef oracle_status() -> str:\n    conn = None\n    try:\n        conn = get_connection()\n        return "connected"\n    except Exception:\n        return "disconnected"\n    finally:\n        if conn is not None:\n            conn.close()\n\n\ndef fetch_metadata() -> tuple[list[dict], list[dict], str]:\n    """Récupère les colonnes d\'aide dynamiquement.\n\n    - Les nouveaux utilisateurs apparaissent automatiquement, sauf s\'ils sont dans HIDDEN_USERS_EXACT.\n    - Les nouvelles tables apparaissent automatiquement, sauf si elles matchent les règles HIDDEN_OBJECTS_*.\n    - Ces filtres ne s\'appliquent qu\'à l\'affichage des colonnes, pas aux requêtes utilisateur.\n    """\n    global _METADATA_CACHE\n\n    with _METADATA_CACHE_LOCK:\n        if _METADATA_CACHE is not None:\n            users, objects, status, timestamp = _METADATA_CACHE\n            elapsed = time_module.time() - timestamp\n            if elapsed < _METADATA_CACHE_TTL_SECONDS:\n                print(f"[METADATA_CACHE_HIT] (cached {elapsed:.1f}s ago)")\n                return users, objects, status\n\n    conn = None\n    cur = None\n    users: list[dict] = []\n    objects: list[dict] = []\n    status = "disconnected"\n    try:\n        conn = get_connection()\n        cur = conn.cursor()\n        oracle_table = get_oracle_table()\n\n        user_sql = (\n            f"SELECT DBUSERNAME, COUNT(*) AS ACTIONS FROM {oracle_table} "\n            f"WHERE {_hidden_users_condition(\'DBUSERNAME\')} "\n            "GROUP BY DBUSERNAME ORDER BY ACTIONS DESC FETCH FIRST 500 ROWS ONLY"\n        )\n        cur.execute(user_sql)\n        users = [{"name": str(r[0]), "actions": int(r[1])} for r in cur.fetchall()]\n\n        obj_sql = (\n            f"SELECT OBJECT_NAME, COUNT(*) AS ACTIONS FROM {oracle_table} "\n            f"WHERE {_hidden_objects_condition(\'OBJECT_NAME\')} "\n            "GROUP BY OBJECT_NAME ORDER BY ACTIONS DESC FETCH FIRST 500 ROWS ONLY"\n        )\n        cur.execute(obj_sql)\n        objects = [{"name": str(r[0]), "actions": int(r[1])} for r in cur.fetchall()]\n\n        status = "connected"\n    except Exception as exc:\n        print(f"[METADATA_ERROR] {exc}")\n        status = "disconnected"\n    finally:\n        if cur is not None:\n            cur.close()\n        if conn is not None:\n            conn.close()\n\n    with _METADATA_CACHE_LOCK:\n        _METADATA_CACHE = (users, objects, status, time_module.time())\n\n    return users, objects, status\n'

NLP_CONTENT = 'import os\nimport re\nfrom typing import Any\n\nfrom app.config import settings\nfrom app.services.settings_service import get_fetch_limit, get_oracle_table\n\ntry:\n    import torch\n    from peft import PeftModel\n    from transformers import AutoModelForCausalLM, AutoTokenizer\n    \n    _MODEL_STACK_AVAILABLE = True\nexcept Exception:\n    torch = None\n    PeftModel = None\n    AutoModelForCausalLM = None\n    AutoTokenizer = None\n    _MODEL_STACK_AVAILABLE = False\n\ndef _system_prompt(table_name: str) -> str:\n    # IMPORTANT: doit rester strictement aligne sur le SYSTEM_PROMPT_TRAIN\n    # du notebook (cellule 12) pour eviter toute divergence Colab vs prod.\n    # Le notebook V13 entraine avec "Table : ORACLE_AUDIT_TRAIL" comme\n    # nom logique stable. Le _post_process_sql() ci-dessous remappe ensuite\n    # vers la vraie table prod (table_name = get_oracle_table()).\n    # Cela permet de changer la table prod sans re-entrainer le LoRA.\n    return (\n        "Tu es un expert SQL Oracle specialise en audit.\\n"\n        "Table : ORACLE_AUDIT_TRAIL\\n"\n        "Colonnes reelles : ID, AUDIT_TYPE, SESSIONID, OS_USERNAME, USERHOST, TERMINAL, "\n        "AUTHENTICATION_TYPE, DBUSERNAME, CLIENT_PROGRAM_NAME, OBJECT_SCHEMA, OBJECT_NAME, "\n        "SQL_TEXT, SQL_BINDS, EVENT_TIMESTAMP, ACTION_NAME, INSTANCE.\\n"\n        "REGLES ABSOLUES :\\n"\n        "1. Tu ne dois interroger qu\'une seule table : ORACLE_AUDIT_TRAIL.\\n"\n        "2. N\'utilise jamais DBA_USERS, ALL_USERS, USER_USERS ni aucune autre table ou vue.\\n"\n        "3. Pour compter des utilisateurs, utilise COUNT(DISTINCT DBUSERNAME) et ignore les NULL.\\n"\n        "4. Connexions : toujours WHERE ACTION_NAME=\'LOGON\'.\\n"\n        "5. Deconnexions : toujours WHERE ACTION_NAME=\'LOGOFF\'.\\n"\n        "6. Heures : SYSDATE-N/24. Jours : SYSDATE-N. Minutes : SYSDATE-N/1440.\\n"\n        "7. Si question sur un utilisateur ET un objet : WHERE DBUSERNAME=\'X\' AND OBJECT_NAME=\'Y\'.\\n"\n        "8. Poste, machine, terminal, hote reseau : utiliser USERHOST.\\n"\n        "9. Horaire nocturne : utiliser TO_CHAR(EVENT_TIMESTAMP,\'HH24\').\\n"\n        "10. Reponds uniquement en SQL Oracle valide, sans explication.\\n"\n        "11. SELECT uniquement. Jamais INSERT, UPDATE, DELETE, DROP ou ALTER en operation reelle.\\n"\n        "12. Tri par date : ORDER BY EVENT_TIMESTAMP DESC.\\n"\n        "13. Limite si necessaire avec FETCH FIRST N ROWS ONLY."\n    )\n\n_TOKENIZER: Any = None\n_MODEL: Any = None\n_DEVICE: Any = None\n_MODEL_ERROR: str | None = None\n\n\ndef _strip_sql_comments(sql: str) -> str:\n    sql = re.sub(r"--.*?$", "", sql, flags=re.MULTILINE)\n    sql = re.sub(r"/\\*.*?\\*/", "", sql, flags=re.DOTALL)\n    return sql\n\n\ndef model_status() -> tuple[str, str | None]:\n    global _TOKENIZER, _MODEL, _DEVICE, _MODEL_ERROR\n\n    if _MODEL is not None and _TOKENIZER is not None:\n        return "loaded", None\n    if _MODEL_ERROR:\n        return "error", _MODEL_ERROR\n    if not _MODEL_STACK_AVAILABLE:\n        _MODEL_ERROR = "torch/transformers/peft indisponibles"\n        return "error", _MODEL_ERROR\n\n    try:\n        _TOKENIZER = AutoTokenizer.from_pretrained(settings.model_dir)\n        if _TOKENIZER.pad_token is None:\n            _TOKENIZER.pad_token = _TOKENIZER.eos_token\n\n        base = AutoModelForCausalLM.from_pretrained(settings.model_dir)\n        _MODEL = PeftModel.from_pretrained(base, settings.lora_dir)\n        _MODEL.eval()\n        _DEVICE = torch.device("cpu")\n        _MODEL.to(_DEVICE)\n        return "loaded", None\n    except Exception as exc:\n        _MODEL_ERROR = str(exc)\n        _TOKENIZER = None\n        _MODEL = None\n        _DEVICE = None\n        return "error", _MODEL_ERROR\n\n\ndef apply_default_row_limit(sql: str, default_limit: int = 200) -> str:\n    su = sql.upper()\n    if "FETCH FIRST" in su or "COUNT(" in su or "GROUP BY" in su:\n        return sql\n    if not su.startswith(("SELECT", "WITH")):\n        return sql\n    sql_no_sc = sql.rstrip().rstrip(";").rstrip()\n    return f"{sql_no_sc} FETCH FIRST {default_limit} ROWS ONLY"\n\n\ndef _post_process_sql(sql: str) -> str:\n    # Normalize trained placeholder table names to runtime Oracle table.\n    return re.sub(r"\\bORACLE_AUDIT_TRAIL\\b", get_oracle_table(), sql, flags=re.IGNORECASE)\n\n\ndef _clean_sql(raw: str, question: str = "") -> str:\n    sql = (raw or "").strip()\n    sql = re.sub(r"```sql", "", sql, flags=re.IGNORECASE)\n    sql = re.sub(r"```", "", sql)\n    sql = re.sub(r"^(SQL\\s*:|Requ[eê]te\\s*:|R[eé]ponse\\s*:)\\s*", "", sql, flags=re.IGNORECASE)\n\n    for kw in ["SELECT", "INSERT", "UPDATE", "DELETE", "WITH", "CREATE", "DROP", "ALTER", "GRANT", "REVOKE"]:\n        idx = sql.upper().find(kw)\n        if idx != -1:\n            sql = sql[idx:]\n            break\n\n    if ";" in sql:\n        sql = sql[: sql.index(";") + 1]\n\n    sql = _post_process_sql(sql.strip())\n    sql = apply_default_row_limit(sql, get_fetch_limit())\n    return sql.rstrip().rstrip(";") + ";"\n\n\ndef _generate_sql_with_model(question: str) -> str:\n    status, err = model_status()\n    if status != "loaded":\n        raise RuntimeError(f"TinyLlama indisponible ({err})")\n\n    oracle_table = get_oracle_table()\n    prompt = (\n        f"<|system|>{_system_prompt(oracle_table)}<|end|>"\n        f"<|user|>{question}<|end|>"\n        "<|assistant|>"\n    )\n    inputs = _TOKENIZER(\n        prompt,\n        return_tensors="pt",\n        truncation=True,\n        max_length=1024,\n    ).to(_DEVICE)\n    with torch.no_grad():\n        out = _MODEL.generate(\n            **inputs,\n            max_new_tokens=settings.max_sql_tokens,\n            do_sample=False,\n            pad_token_id=_TOKENIZER.eos_token_id,\n        )\n\n    raw = _TOKENIZER.decode(out[0][inputs["input_ids"].shape[1] :], skip_special_tokens=True)\n    return _clean_sql(raw, question)\n\n\ndef validate_sql_guardrails(sql: str) -> tuple[bool, str]:\n    # Garde-fous désactivés temporairement\n    return True, "OK"\n\n\ndef generate_sql_from_question(question: str) -> str:\n    return _generate_sql_with_model(question)\n\n'


def backup(path: Path) -> None:
    if not path.exists():
        return
    backup_path = path.with_name(path.name + BACKUP_SUFFIX)
    if not backup_path.exists():
        backup_path.write_text(path.read_text(encoding="utf-8"), encoding="utf-8")
        print(f"Sauvegarde créée : {backup_path}")
    else:
        print(f"Sauvegarde déjà présente : {backup_path}")


def main() -> None:
    if not BACKEND.exists() or not MAIN_PATH.exists():
        raise SystemExit("Erreur : lance ce script depuis la racine du projet, par exemple C:\\dossier3\\nlp")

    print("=" * 72)
    print("STABILISATION AUDIT AI — RETOUR À UN BACKEND NON RIGIDE")
    print("=" * 72)
    print(f"Racine projet : {ROOT}")
    print(f"Date          : {datetime.now()}")
    print()

    for path in (MAIN_PATH, ORACLE_PATH, NLP_PATH):
        backup(path)

    MAIN_PATH.write_text(MAIN_CONTENT, encoding="utf-8")
    ORACLE_PATH.write_text(ORACLE_CONTENT, encoding="utf-8")
    NLP_PATH.write_text(NLP_CONTENT, encoding="utf-8")

    # On ne supprime pas le fichier dynamique pour conserver l'historique,
    # mais il n'est plus importé par le backend stable.
    if DYNAMIC_PATH.exists():
        print(f"Fichier dynamique laissé en place mais désactivé par absence d'import : {DYNAMIC_PATH}")

    print()
    print("Correction appliquée.")
    print("Le backend ne réécrit plus les vraies requêtes SQL du modèle.")
    print("Les filtres TEST/VROMUALD restent seulement pour l'affichage des colonnes d'aide.")
    print()
    print("Redémarre ensuite le backend :")
    print("cd backend")
    print("uvicorn app.main:app --host 0.0.0.0 --port 8000 --reload")
    print("=" * 72)


if __name__ == "__main__":
    main()
